   208|export async function updateRequestStatus(
   209|  requestId: string,
   210|  status: EquipmentRequest['status'],
   211|  currentUid: string
   212|): Promise<void> {
   213|  const db = getFirebaseDb();
   214|  console.log('[Firestore] Updating request status:', requestId, '->', status);
   215|
   216|  const snap = await getDoc(doc(db, 'equipmentRequests', requestId));
   217|  if (!snap.exists()) throw new Error('Request not found');
   218|
   219|  const request = snap.data();
   220|  const isProvider = request.providerUid === currentUid;
   221|  const isCustomer = request.customerUid === currentUid;
   222|
   223|  const validTransitions: Record<string, { allowed: string[]; who: 'provider' | 'customer' | 'both' }> = {
   224|    pending: { allowed: ['accepted', 'rejected', 'cancelled'], who: 'both' },
   225|    accepted: { allowed: ['in_progress', 'cancelled'], who: 'both' },
   226|    in_progress: { allowed: ['completed'], who: 'provider' },
   227|  };
   228|
   229|  const current = request.status as string;
   230|  const rule = validTransitions[current];
   231|
   232|  if (!rule || !rule.allowed.includes(status)) {
   233|    throw new Error(`Invalid status transition: ${current} -> ${status}`);
   234|  }
   235|
   236|  if (rule.who === 'provider' && !isProvider) {
